    def longestValidParentheses(self, s: str) -> int:
        stack = [-1]  # sentinel
        max_len = 0

        for i, c in enumerate(s):
            if c == '(':
                stack.append(i)
            else:
                stack.pop()
                if not stack:
                    stack.append(i)  # new base
                else:
                    max_len = max(max_len, i - stack[-1])

        return max_len

